open Lean Nat

def init (main : Unit) : Unit := do
  let w := ⟨nonneg (Nat.ofNatU32 <| __VERIFIER_nondet_uint ())⟩
  let is_divisible1 := correct_version w
  let is_divisible2 := student_version w
  let overflow : Prop := w > ofNat (10000000)
  let _ : Bool := is_divisible1 = is_divisible2
  return ()

def G (p : Prop) : Prop := ∀ (s : Stream Prop), p ∧ s.is_nonempty → s.item ≠ p  → G p (s.push p s)

def LTL (p : Prop) : Prop := ∀ (s : Stream Prop), G p s

def overflow : Prop := w > ofNat (10000000)

def _root._ (_ : init main) : Prop := LTL (~overflow)

