import Mathlib

open Lean.Elab.Tactic.Simple
open Lean.Elab.Tactics
open Lean.Syntax
open Lean.Parser.Tactic

namespace Main

open CInt

def boolKind : Type := ∀ (a : Type), Type
def false : boolKind a := ∑ (b : a), {carrier := false, payload := b}
def true : boolKind a := ∑ (b : a), {carrier := true, payload := b}

inductive CCode : Type :=
| CProgram : String → List (Expr CInt.int) → CCode
| CStatement : CStatement → CCode
and CStatement : Type :=
| CExprStatement : Expr CInt.int → CStatement
| CIfStatement : Expr CInt.int → CStatement → CStatement → CStatement
| CWhileStatement : Expr CInt.int → CStatement → CStatement

def init (code : CCode) : Expr :=
begin
  match code with
  | .CProgram ("main" :: args, stmts) => do {
      let env ← get_env
      let i   ← alloc_var "i" int
      let j   ← alloc_var "j" int
      let stmtList ← mapM (fun stmt => do {
          let expr ← init stmt
          return (CExprStatement expr)
        }) stmts
      let body ← do {
          let cond ← init (List.nth stmts 0)
          let thenBranch ← init (List.nth stmts 2)
          let elseBranch ← match (List.nth stmts 1) with
              | .CWhileStatement (_cond, _stmt, body) => init body
              | _ => return (CExprStatement (CInt.lit (CInt.int.zero)))
          return (CIfStatement cond thenBranch elseBranch)
        }
      return (CWhileStatement (CInt.lit (CInt.int.lit (int.ofNat 100))) body)
    }
  | _ => return (CExprStatement (CInt.lit (CInt.int.zero)))
end

def LTL (p : Prop) : Prop := ∀ σ : Stream Nat, p σ.head ∧ ∀ i, p (σ.shift (i + 1))

def F : Prop := ∀ i, ¬ (CInt.lit (CInt.int.lit (int.ofNat i)) = CInt.lit (CInt.int.lit (int.ofNat 1)))

def end : Expr := CInt.lit (CInt.int.lit (int.ofNat 100))

def main : Prop := CHECK (init mainCode, LTL F)

end Main

def mainCode : CCode := .CProgram (["main"], [
  .CStatement (.CExprStatement (CInt.assignVar! "i" (CInt.lit (CInt.int.lit (int.ofNat 0))))),
  .CStatement (
    .CWhileStatement (
      CInt.compare! (CInt.var! "i") (CInt.lit (CInt.int.lit (int.ofNat 100))),
      (.CStatement (
        .CStatement (.CExprStatement (CInt.assignVar! "j" (CInt.lit (CInt.int.lit (int.ofNat 0))))),
        .CStatement (.CWhileStatement (
          CInt.compare! (CInt.var! "j") (CInt.lit (CInt.int.lit (int.ofNat 1))),
          .CStatement (.CExprStatement (CInt.assignVar! "j" (CInt.addVar! "j" (CInt.int.one))))
        ))
      )),
      .CStatement (.CExprStatement (CInt.assignVar! "i" (CInt.addVar! "i" (CInt.int.zero)))),
    ])
])

#check mainCode
#check init
#check main
#check LTL F
#check (init mainCode)
#check (LTL F)
#check (main)
