namespace Fibo

def fib (n : ℕ) : ℕ :=
if h : n < 1 then 0
else if h : n = 1 then 1
else fib (n - 1) + fib (n - 2)

def main : ℕ :=
15

def init := do
  let x := main
  fib x

def call_reach_error : Prop :=
false

def G : Prop :=
∀ (s : ℕ), ℕ.recOn s (λ n h, ¬ call_reach_error) _

def check : Prop :=
init ∧ G

def LTL_G_not_call_reach_error : Prop :=
∀ (s : ℕ), ∀ (p : ℕ → Prop), p s → ∀ (t : ℕ), p t → G.recOn s (λ n h, p n.succ h) t

theorem check : True :=
(check.elim ∥ init, LTL_G_not_call_reach_error.mpr (λ _ _, False.elim _)).elim

end Fibo

