open Lean.Elab.Tactics
open Lean.Parser.Tactics

def F := ∀ (x : ℕ) ∀ (y : ℕ), x > y → x' < y'

def init' : Nat → Nat → Nat → Option Nat
| 0 _ _ := some 0
| (n + 1) x y := do
  let x' ← init' n x y
  let y' ← init' n x y
  some (if (x' > y') then (x' - 1) else if (x' = y') then (y' - 1) else x')

def init (main : Unit) : Option Nat := do
  let x ← init' <$> (random ℕ)
  let y ← init' <$> (random ℕ)
  let z ← init' <$> (random ℕ)
  some (match init' x y z with
    | some n => n
    | none => none)

def main' : Option Nat := init main

def LTL_F_end (p : Option Nat) : Prop := match p with
  | some n => ∀ (s : Stream Nat), ¬ (n ∈ s)
  | none => true

def CHECK : Prop := LTL_F_end <|> (main' = some 0)

