import Mathlib

open Lean.Elab.Tactics
open Lean.Elab.Expression
open Lean.Syntax
open Lean.Util.String

def array (n : Nat) : Type := Array (Nat)
def init : Expression => Expression := λ e, do! {
  let [a, array_size] ← freshX "a array_size" <| e.getArgs,
  let arr ← freshX "arr" <| mkConst "array" [n],
  let a_expr ← mkConst "a" [],
  let arraySizeExpr ← mkConst "array_size" [],
  let selectionSort ← mkConst "SelectionSort" [],
  let stmt ← mkLit (mkApp selectionSort [a_expr, arraySizeExpr]),
  let main ← mkConst "main" [],
  let mainStmt ← mkApp main [],
  let initExpr ← mkApp init [mainStmt],
  let ltlG ← mkConst "LTL.G" [],
  let validFree ← mkApp ltlG [mkConst "valid-free" []],
  let validDeref ← mkApp ltlG [mkConst "valid-deref" []],
  let validMemtrack ← mkApp ltlG [mkConst "valid-memtrack" []],
  let check ← mkConst "CHECK" [],
  mkApp check [initExpr, mkApp (mkApp validFree []) [],
             mkApp (mkApp validDeref []) [],
             mkApp (mkApp validMemtrack []) []]
}

def SelectionSort (a : Array Nat) : Expression := do! {
  let arraySize ← getSize a,
  let mut i ← mkConst "i" Nat.zero,
  let mut temp ← freshX "temp" Nat.zero,
  let mut min ← mkConst "min" Nat.zero,
  let rec loop : Expression := do! {
    let j ← mkConst "j" (mkAdd i Nat.one),
    let minIndex ← if (mkApp (mkApp lt [mkApp (get a i), mkApp (get a j)]) []) then mkConst "j" Nat.zero else min,
    let tempVal ← get (get a minIndex),
    let aSwap ← mkApp (mkApp swap [mkApp (get a i), mkApp (get a minIndex)]) [],
    let iVal ← get i,
    let newMinIndex ← mkConst "min" (mkAdd iVal Nat.one),
    let newMin ← get (get a newMinIndex),
    let newTemp ← freshX "newTemp" Nat.zero,
    let newTempVal ← get newTemp,
    let newTempSwap ← mkApp (mkApp swap [mkApp (get a i), mkApp (get a newMinIndex)]) [],
    let newI ← mkConst "i" (mkAdd iVal Nat.one),
    let newTempValLe ← mkApp (mkApp le [newTempVal, tempVal]) [],
    let leqTempValNewTemp ← mkApp (mkApp leq [tempVal, newTempVal]) [],
    let leqTempValMin ← mkApp (mkApp leq [newTempVal, minVal]) [],
    let andTemp ← mkApp (mkApp and [leqTempValNewTemp, leqTempValMin]) [],
    let newTempSwapLeMin ← mkApp (mkApp le [newTemp, minIndex]) [],
    let leqTempMinNewTemp ← mkApp (mkApp leq [min, newTemp]) [],
    let andTemp1 ← mkApp (mkApp and [leqTempMinNewTemp, andTemp]) [],
    let loop ← if (mkApp (mkApp and [andTemp1, andTemp]) []) then do! {
        set i newI,
        set temp newTemp,
        set min newMinIndex,
        loop
      } else mkConst "loop.end" [],
    let body ← mkApp loop [],
    let statement ← mkApp (mkApp stmt [a, arraySize]) [],
    body
  },
  mkApp loop []
}

def main : Expression := do! {
  let a ← mkConst "a" (mkApp array Nat.zero) [],
  let arraySize ← mkConst "array_size" [],
  let mainStmt ← mkApp (mkConst "SelectionSort" []) [],
  let stmt ← mkApp mainStmt [a, arraySize],
  let mainExpr ← mkApp (mkConst "main" []) [],
  let mainStmt2 ← mkApp mainExpr [],
  let mainStmt3 ← mkApp stmt [],
  mkApp mainStmt3 []
}

init main.elabUndefined

