import Mathlib

open Lean.Elab.Tactics
open Lean.Parser.Tactics
open Lean.Meta
open Lean.Syntax
open Lean.Util.Inhabited

def init : IO Unit := do
  set_option pp.all false in
  #eval (main)

def valid_free : Prop := ∀ i : Nat, 0 < i < (N : Nat) → a i : Ptr ptr Nat → box i = box (i + 1)

def valid_deref : Prop := ∀ i : Nat, 0 < i < (N : Nat) → a !i = i + 1

def valid_memtrack : Prop := ∀ i : Nat, ∃ p : Ptr ptr Nat, i = index p (a : Ptr ptr Nat)

def main : IO Unit := do
  let N' ← nat.nondet,
  let a' ← alloc N' <|> pure (error "malloc failed"),
  let ℳ := ∀ i : Nat, a i = (i + 1) * (i + 1)
  let ℳ' := ∀ i : Nat, i < N' → a (i.succ) = (i + 1) * (i + 1)
  let ℳ'' := ∀ i : Nat, i < N' → a i = a (i.succ) - i
  let ℳ''' := ℳ && ℳ' && ℳ''
  let ℳ⁴ := ∀ i : Nat, i < N' → a i = i + 1
  let ℳ⁵ := valid_free && valid_deref && valid_memtrack
  have : init(main) = pure unit,
  have hℳ⁵ : ℳ⁵,
  have hℳ⁴ : LTL.G valid_memtrack.symm,
  have hℳ''' : LTL.G ℳ''' := by {
    apply LTL.until (λ h, LTL.next h) hℳ⁴ hℳ'''
  },
  have hℳ'' : LTL.G ℳ'', := by {
    apply LTL.until (λ h, LTL.next h) hℳ⁴ hℳ''
  },
  have hℳ' : LTL.G ℳ', := by {
    apply LTL.until (λ h, LTL.next h) hℳ⁴ hℳ'
  },
  have hℳ : LTL.G ℳ, := by {
    apply LTL.until (λ h, LTL.next h) hℳ⁴ hℳ
  },
  have hℳ⁴' : LTL.G ℳ⁴, := by {
    apply LTL.until (λ h, LTL.next h) hℳ⁴ hℳ⁴
  },
  let ℳ⁶ := ∀ i : Nat, i < N' → a i = i
  have hℳ⁶ : LTL.G ℳ⁶, := by {
    apply LTL.until (λ h, LTL.next h) hℳ⁴ hℳ⁶
  },
  have h : LTL "G (valid-free && valid-deref && valid-memtrack)" := LTL.and hℳ⁵ hℳ⁴' && LTL.and hℳ⁵ hℳ⁴ && LTL.and hℳ⁵ hℳ⁴ && LTL.and hℳ⁵ hℳ⁴ && LTL.and hℳ⁵ hℳ⁴ && LTL.and hℳ⁵ hℳ⁶,
  let _ := trace "Checking property:" $ h,
  pure unit

CHECK (init (main()), h)

