import Mathlib

open Lean.Elab.Tactic.Simple
open Lean.Elab.Tactic.Expressions
open Lean.Elab.Tactic.Term

def reach_error : Unit :=
  let ⁅str⁆ := "reach_error"
  let ⁅file⁆ := "array_1-2.c"
  let ⁅line⁆ := 3
  let ⁅msg⁆ := "0"
  let assert_fail : (String × String × Nat × String) → Unit := ∥x => do
    let _ := abort
    let _ := throwError (Message.mkStr "assertion failed" [msg.get, file.get, line.toString, x.get])
  let _ := reach_error := fun () => assert_fail ("", "reach_error", 0, "")

def __VERIFIER_assert (cond : Bool) : Unit :=
  if cond then return () else do
    let ⁅_⁆ := reach_error
    abort

def A (i : Nat) : Int :=
  if i < 2048 then A![i] else failwith "Array index out of bounds"

def init (): Unit := do
  let A := [| ∀ i, i, i < 1024 |]
  return A

def valid_free : Prop :=
  ∀ i, i < 1024 → A i = i

def valid_deref : Prop :=
  ∀ i, A i = i → A (succ i) = succ i

def valid_memtrack : Prop :=
  ∀ i j, i ≠ j → A i ≠ A j

def main : Unit := do
  let A := init ()
  let ℳ := ∃ i, valid_free i ∧ valid_deref i ∧ valid_memtrack i
  let _ := assert (ℳ)
  return ()

Set Tactic.interactiveMode true
set_option pp.all false

def check_property : Prop → Expr → Expr := ∥prop, p => do
  let ℳ := ∃ i, prop i
  let _ := assert (ℳ)
  return p

def _root_.main : Unit := do
  let _ := CHC.check (check_property valid_free (getConst ``init'' []))
  let _ := CHC.check (check_property valid_deref (getConst ``init'' []))
  let _ := CHC.check (check_property valid_memtrack (getConst ``init'' []))
  let _ := CHC.runMain
  return ()
